import{_ as r,o,c as e,ag as a}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/paralloop.png",m=JSON.parse('{"title":"Paralloop","description":"","frontmatter":{},"headers":[],"relativePath":"modules/paralloop.md","filePath":"modules/paralloop.md"}'),n={name:"modules/paralloop.md"};function d(l,t,i,p,g,u){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="paralloop" tabindex="-1">Paralloop <a class="header-anchor" href="#paralloop" aria-label="Permalink to &quot;Paralloop&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>8-layer parallel looper where each recording goes to its own buffer. First recording sets master loop length (max 1.5s). Subsequent layers auto-record for the same duration. Per-layer speed changes pitch within fixed time window. Envelope followers generate trigger outputs routable to 4 buses for driving DrumMachine or MultiSamplePlayer.</p><img src="'+s+'" alt="paralloop module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio input.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio input.</td></tr><tr><td><strong>ploop_speed</strong></td><td>Speed CV (0.5 = no change, 0 = 0.25x, 1 = 4x).</td></tr><tr><td><strong>ploop_level</strong></td><td>Per-layer playback level 0-1. Acts as a per-layer VCA before the master mix.</td></tr><tr><td><strong>ploop_start</strong></td><td>Loop start position 0-1 within the master loop window. Sweep to scrub the playback offset.</td></tr><tr><td><strong>ploop_length</strong></td><td>Loop length 0-1. Shrink to play only a fragment of the master loop; full = entire window.</td></tr><tr><td><strong>ploop_mix</strong></td><td>Dry/wet mix CV.</td></tr><tr><td><strong>ploop_trig_route</strong></td><td>Trigger bus routing CV. 0 = none, 1-4 selects which trigger bus (trig1..trig4) the current layer&#39;s envelope follower drives.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left mixed output.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right mixed output.</td></tr><tr><td><strong>trig1</strong></td><td>Trigger bus 1 (1ms pulses from assigned layers).</td></tr><tr><td><strong>trig2</strong></td><td>Trigger bus 2.</td></tr><tr><td><strong>trig3</strong></td><td>Trigger bus 3.</td></tr><tr><td><strong>trig4</strong></td><td>Trigger bus 4.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Bank 1: Btn1=record/play, Btn2=mute, Btn3=lock, Btn4=reverse. Pot1=speed, Pot2=level, Pot3=loop start, Pot4=loop length. Bank 2: Btn1/2=navigate layers, Btn3=mixdown (merges unlocked layers), Btn4=undo. Bank 2 Pot1-4=trigger routing for 4 layers at a time (0=none, 1-4=bus). Lock layers to protect them from mixdown.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const c=r(n,[["render",d]]);export{m as __pageData,c as default};
